class AIPostRenderer{static ANIMATION_DELAY_MS=30;static AI_EXPLANATION_SELECTOR=".ai-explanation";static AI_TAG_SELECTOR=".ai-tag";init(){this.tagElement=document.querySelector(AIPostRenderer.AI_TAG_SELECTOR),this.isAnimating=!1,this.aiContent=PAGE_CONFIG?.ai_text||"",this.explanationElement=document.querySelector(AIPostRenderer.AI_EXPLANATION_SELECTOR),this.renderAIContent()}renderAIContent(){this.validateElements()&&this.aiContent&&(this.prepareAnimation(),this.startTextAnimation())}validateElements(){return this.explanationElement&&this.tagElement&&!this.isAnimating}prepareAnimation(){this.isAnimating=!0,this.tagElement.classList.add("loadingAI"),this.explanationElement.innerHTML=""}startTextAnimation(){const e=t=>{t>=this.aiContent.length?this.completeAnimation():(this.appendCharacter(this.aiContent[t]),setTimeout(()=>e(t+1),AIPostRenderer.ANIMATION_DELAY_MS))};e(0)}appendCharacter(t){const e=document.createElement("span");e.className="char",e.textContent=t,this.explanationElement.appendChild(e)}completeAnimation(){this.isAnimating=!1,this.tagElement.classList.remove("loadingAI")}}const ai=new AIPostRenderer;